const https = require('https');
const fs = require('fs');

const cert = fs.readFileSync('/certs/teller/certificate.pem');
const key = fs.readFileSync('/certs/teller/private_key.pem');

// Read tokens from environment variable (comma-separated)
const tokens = (process.env.TELLER_TOKENS || '').split(',').filter(t => t.trim());

if (tokens.length === 0) {
  throw new Error('No TELLER_TOKENS configured');
}

const makeRequest = (path, token) => {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'api.teller.io',
      path: path,
      method: 'GET',
      cert: cert,
      key: key,
      headers: {
        'Authorization': 'Basic ' + Buffer.from(token + ':').toString('base64')
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          resolve(JSON.parse(data));
        } catch (e) {
          resolve([]);
        }
      });
    });
    req.on('error', reject);
    req.end();
  });
};

const accountRecords = [];
const balanceRecords = [];
const transactionRecords = [];

// Loop through each token (enrollment)
for (const token of tokens) {
  const accounts = await makeRequest('/accounts', token);
  if (!Array.isArray(accounts)) continue;

  for (const a of accounts) {
    accountRecords.push({
      teller_account_id: a.id,
      enrollment_id: a.enrollment_id,
      institution_name: a.institution?.name || null,
      institution_id: a.institution?.id || null,
      account_name: a.name,
      account_type: a.type,
      account_subtype: a.subtype,
      account_status: a.status,
      currency: a.currency,
      last_four: a.last_four
    });
  }

  for (const a of accounts) {
    const bal = await makeRequest('/accounts/' + a.id + '/balances', token);
    balanceRecords.push({
      teller_account_id: a.id,
      ledger_balance: parseFloat(bal.ledger) || 0,
      available_balance: parseFloat(bal.available) || 0
    });
  }

  for (const a of accounts) {
    const txns = await makeRequest('/accounts/' + a.id + '/transactions', token);
    if (!Array.isArray(txns)) continue;
    for (const t of txns) {
      transactionRecords.push({
        teller_transaction_id: t.id,
        teller_account_id: a.id,
        transaction_date: t.date,
        description: t.description,
        amount: parseFloat(t.amount) || 0,
        status: t.status,
        type: t.type,
        category: t.details?.category || null,
        merchant_name: t.details?.counterparty?.name || null,
        merchant_category: t.details?.counterparty?.type || null,
        running_balance: parseFloat(t.running_balance) || null
      });
    }
  }
}

return [{
  json: {
    accounts: accountRecords,
    balances: balanceRecords,
    transactions: transactionRecords,
    summary: {
      tokenCount: tokens.length,
      accountCount: accountRecords.length,
      balanceCount: balanceRecords.length,
      transactionCount: transactionRecords.length
    }
  }
}];

